args.query:
SELECT o.Id, o.Name, o.StageName, o.Amount, o.CloseDate, o.Probability, o.Description
FROM Opportunity o
WHERE trim(replace(o.ContactId,'#','')) IN (
    SELECT trim(replace(ConvertedContactId,'#','')) FROM Lead WHERE trim(replace(Id,'#',''))='00QWt0000089AekMAE'
)
   OR trim(replace(o.AccountId,'#','')) IN (
    SELECT trim(replace(ConvertedAccountId,'#','')) FROM Lead WHERE trim(replace(Id,'#',''))='00QWt0000089AekMAE'
)
ORDER BY o.CreatedDate DESC
LIMIT 10;

